import React, { useState, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const SEQ_LEN = 8;
const Q_DATA = [1.5, 0.8, 1.2, 0.5, 1.8, 0.3, 1.0, 0.6];
const K_DATA = [0.4, 1.6, 0.7, 1.3, 0.5, 1.4, 0.9, 1.7];
const V_DATA = [10, 20, 30, 40, 50, 60, 70, 80];

function computeSparseAttention(Q, K, V, windowSize) {
  const n = Q.length;
  const scale = 1.0;
  const attnMatrix = [];
  const outputs = [];
  const windowRanges = [];

  for (let i = 0; i < n; i++) {
    const start = Math.max(0, i - windowSize);
    const end = Math.min(n, i + windowSize + 1);
    windowRanges.push({ start, end });

    const scores = [];
    for (let j = start; j < end; j++) {
      scores.push(Q[i] * K[j] / scale);
    }

    const maxScore = Math.max(...scores);
    const expScores = scores.map(s => Math.exp(s - maxScore));
    const sumExp = expScores.reduce((a, b) => a + b, 0);
    const weights = expScores.map(e => e / sumExp);

    const row = new Array(n).fill(0);
    for (let j = start; j < end; j++) {
      row[j] = weights[j - start];
    }
    attnMatrix.push(row);

    let out = 0;
    for (let j = start; j < end; j++) {
      out += row[j] * V[j];
    }
    outputs.push(out);
  }

  const totalOps = windowRanges.reduce((sum, r) => sum + (r.end - r.start), 0);
  return { attnMatrix, outputs, windowRanges, totalOps };
}

export default function App() {
  const [windowSize, setWindowSize] = useState(2);
  const [selectedToken, setSelectedToken] = useState(3);
  const [hoveredCell, setHoveredCell] = useState(null);

  const sparse = useMemo(() => computeSparseAttention(Q_DATA, K_DATA, V_DATA, windowSize), [windowSize]);
  const full = useMemo(() => computeSparseAttention(Q_DATA, K_DATA, V_DATA, SEQ_LEN - 1), []);

  const selRange = sparse.windowRanges[selectedToken];
  const selWeights = sparse.attnMatrix[selectedToken];
  const selOutput = sparse.outputs[selectedToken];
  const fullOutput = full.outputs[selectedToken];

  const cellSize = 36;
  const labelW = 28;

  const opsPercent = Math.round((sparse.totalOps / (SEQ_LEN * SEQ_LEN)) * 100);
  const opsSaved = SEQ_LEN * SEQ_LEN - sparse.totalOps;

  function getCellBg(row, col) {
    const w = sparse.attnMatrix[row][col];
    const inWindow = col >= sparse.windowRanges[row].start && col < sparse.windowRanges[row].end;
    if (!inWindow) return theme.colors.surfaceAlt;
    const intensity = Math.min(1, w * 2.5);
    const r = Math.round(139 * intensity);
    const g = Math.round(92 * intensity);
    const b = Math.round(246 * intensity);
    return `rgb(${r + Math.round((17 - r) * (1 - intensity))}, ${g + Math.round((17 - g) * (1 - intensity))}, ${b + Math.round((17 - b) * (1 - intensity))})`;
  }

  const maxWeight = Math.max(...selWeights.filter(w => w > 0));

  return (
    <div style={{
      minHeight: '100vh',
      background: theme.colors.background,
      fontFamily: theme.font,
      color: theme.colors.text,
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'flex-start',
      padding: '16px',
      boxSizing: 'border-box',
    }}>
      <div style={{ width: '100%', maxWidth: 560 }}>
        {/* Title */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
          <div style={{ fontSize: 17, fontWeight: 700, letterSpacing: '-0.5px' }}>
            Sparse Window Attention
          </div>
          <div style={{
            fontSize: 11,
            color: theme.colors.textMuted,
            background: theme.colors.surface,
            padding: '4px 10px',
            borderRadius: 6,
          }}>
            Click a token, drag the slider
          </div>
        </div>

        {/* Window Size Slider */}
        <div style={{
          background: theme.colors.surface,
          borderRadius: 10,
          padding: '12px 16px',
          marginBottom: 12,
          display: 'flex',
          alignItems: 'center',
          gap: 14,
        }}>
          <div style={{ fontSize: 12, color: theme.colors.textSecondary, whiteSpace: 'nowrap' }}>
            Window radius
          </div>
          <div style={{ fontSize: 20, fontWeight: 700, color: theme.colors.primary, minWidth: 24, textAlign: 'center' }}>
            {windowSize}
          </div>
          <input
            type="range"
            min={0}
            max={7}
            value={windowSize}
            onChange={e => setWindowSize(Number(e.target.value))}
            style={{ flex: 1, accentColor: theme.colors.primary, cursor: 'pointer' }}
          />
          <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
            <div style={{
              fontSize: 11,
              padding: '3px 8px',
              borderRadius: 4,
              background: opsPercent <= 50 ? 'rgba(163, 230, 53, 0.15)' : opsPercent < 100 ? 'rgba(251, 191, 36, 0.15)' : 'rgba(244, 63, 94, 0.15)',
              color: opsPercent <= 50 ? theme.colors.green : opsPercent < 100 ? theme.colors.yellow : '#f43f5e',
              fontWeight: 600,
            }}>
              {sparse.totalOps}/{SEQ_LEN * SEQ_LEN} ops
            </div>
          </div>
        </div>

        {/* Token Values Row */}
        <div style={{ marginBottom: 8 }}>
          <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 4, marginLeft: labelW + 4 }}>Values (V)</div>
          <div style={{ display: 'flex', gap: 2, marginLeft: labelW + 4 }}>
            {V_DATA.map((v, i) => {
              const inWindow = i >= selRange.start && i < selRange.end;
              const isSelected = i === selectedToken;
              return (
                <div
                  key={i}
                  onClick={() => setSelectedToken(i)}
                  style={{
                    width: cellSize,
                    height: 32,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: 12,
                    fontWeight: isSelected ? 700 : 500,
                    borderRadius: 6,
                    cursor: 'pointer',
                    background: isSelected ? theme.colors.primary : inWindow ? 'rgba(139, 92, 246, 0.2)' : theme.colors.surfaceAlt,
                    color: isSelected ? '#fff' : inWindow ? theme.colors.primary : theme.colors.textMuted,
                    border: isSelected ? '2px solid ' + theme.colors.primary : inWindow ? '1px solid rgba(139, 92, 246, 0.3)' : '1px solid ' + theme.colors.border,
                    transition: 'all 0.25s ease',
                    boxSizing: 'border-box',
                  }}
                >
                  {v}
                </div>
              );
            })}
          </div>
        </div>

        {/* Attention Matrix Heatmap */}
        <div style={{
          background: theme.colors.surface,
          borderRadius: 10,
          padding: '14px 14px 10px 14px',
          marginBottom: 12,
        }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
            <div style={{ fontSize: 12, color: theme.colors.textSecondary, fontWeight: 600 }}>Attention Matrix</div>
            <div style={{ fontSize: 10, color: theme.colors.textMuted }}>
              Row = query, Col = key
            </div>
          </div>

          {/* Column Headers */}
          <div style={{ display: 'flex', marginLeft: labelW + 4, marginBottom: 2 }}>
            {Array.from({ length: SEQ_LEN }).map((_, j) => (
              <div key={j} style={{
                width: cellSize,
                height: 16,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 9,
                color: theme.colors.textMuted,
                marginRight: 2,
              }}>
                {j}
              </div>
            ))}
          </div>

          {/* Matrix Rows */}
          {Array.from({ length: SEQ_LEN }).map((_, i) => (
            <div key={i} style={{ display: 'flex', alignItems: 'center', marginBottom: 2 }}>
              <div style={{
                width: labelW,
                fontSize: 9,
                color: i === selectedToken ? theme.colors.primary : theme.colors.textMuted,
                fontWeight: i === selectedToken ? 700 : 400,
                textAlign: 'right',
                paddingRight: 4,
                transition: 'all 0.2s ease',
              }}>
                T{i}
              </div>
              {Array.from({ length: SEQ_LEN }).map((_, j) => {
                const inWindow = j >= sparse.windowRanges[i].start && j < sparse.windowRanges[i].end;
                const weight = sparse.attnMatrix[i][j];
                const isSelRow = i === selectedToken;
                const isHov = hoveredCell && hoveredCell.r === i && hoveredCell.c === j;
                return (
                  <div
                    key={j}
                    onClick={() => setSelectedToken(i)}
                    onMouseEnter={() => setHoveredCell({ r: i, c: j })}
                    onMouseLeave={() => setHoveredCell(null)}
                    style={{
                      width: cellSize,
                      height: cellSize,
                      marginRight: 2,
                      borderRadius: 4,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: isHov && inWindow ? 9 : 0,
                      fontWeight: 600,
                      color: '#fff',
                      background: getCellBg(i, j),
                      border: isSelRow && inWindow ? '1.5px solid rgba(139, 92, 246, 0.6)' : isSelRow ? '1px solid rgba(139, 92, 246, 0.15)' : '1px solid ' + (inWindow ? 'rgba(139, 92, 246, 0.1)' : 'transparent'),
                      cursor: 'pointer',
                      transition: 'all 0.25s ease',
                      position: 'relative',
                      overflow: 'hidden',
                    }}
                  >
                    {isHov && inWindow ? (weight * 100).toFixed(0) + '%' : ''}
                  </div>
                );
              })}
            </div>
          ))}

          {/* Legend */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginTop: 8, marginLeft: labelW + 4 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 12, height: 12, borderRadius: 3, background: theme.colors.primary }} />
              <span style={{ fontSize: 10, color: theme.colors.textMuted }}>High weight</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 12, height: 12, borderRadius: 3, background: 'rgb(30, 22, 50)' }} />
              <span style={{ fontSize: 10, color: theme.colors.textMuted }}>Low weight</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 12, height: 12, borderRadius: 3, background: theme.colors.surfaceAlt, border: '1px solid ' + theme.colors.border }} />
              <span style={{ fontSize: 10, color: theme.colors.textMuted }}>Outside window</span>
            </div>
          </div>
        </div>

        {/* Selected Token Detail */}
        <div style={{
          background: theme.colors.surface,
          borderRadius: 10,
          padding: '14px 16px',
          marginBottom: 12,
        }}>
          <div style={{ fontSize: 12, color: theme.colors.textSecondary, fontWeight: 600, marginBottom: 10 }}>
            Token {selectedToken} attends to tokens {selRange.start}..{selRange.end - 1}
            <span style={{ color: theme.colors.textMuted, fontWeight: 400 }}>
              {' '}({selRange.end - selRange.start} of {SEQ_LEN} tokens)
            </span>
          </div>

          {/* Weight bars */}
          <div style={{ display: 'flex', gap: 3, alignItems: 'flex-end', height: 54, marginBottom: 8 }}>
            {V_DATA.map((v, j) => {
              const w = selWeights[j];
              const inWindow = j >= selRange.start && j < selRange.end;
              const barH = inWindow ? Math.max(4, (w / maxWeight) * 48) : 0;
              return (
                <div key={j} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: cellSize, gap: 2 }}>
                  {inWindow && (
                    <div style={{
                      fontSize: 9,
                      color: theme.colors.textSecondary,
                      fontWeight: 600,
                      transition: 'all 0.3s ease',
                    }}>
                      {(w * 100).toFixed(0)}%
                    </div>
                  )}
                  <div style={{
                    width: 20,
                    height: barH,
                    borderRadius: 3,
                    background: inWindow ? theme.colors.primary : 'transparent',
                    opacity: inWindow ? 0.4 + w * 1.5 : 0,
                    transition: 'all 0.35s ease',
                  }} />
                </div>
              );
            })}
          </div>

          {/* Computation */}
          <div style={{
            background: theme.colors.surfaceAlt,
            borderRadius: 6,
            padding: '8px 10px',
            fontSize: 11,
            color: theme.colors.textSecondary,
            display: 'flex',
            flexWrap: 'wrap',
            gap: 4,
            alignItems: 'center',
          }}>
            <span style={{ color: theme.colors.textMuted }}>output =</span>
            {V_DATA.map((v, j) => {
              const w = selWeights[j];
              if (w === 0) return null;
              const isLast = j === selRange.end - 1;
              return (
                <span key={j} style={{ transition: 'all 0.3s ease' }}>
                  <span style={{ color: theme.colors.primary }}>{(w).toFixed(2)}</span>
                  <span style={{ color: theme.colors.textMuted }}> x </span>
                  <span style={{ color: theme.colors.text }}>{v}</span>
                  {!isLast && <span style={{ color: theme.colors.textMuted }}> + </span>}
                </span>
              );
            })}
            <span style={{ color: theme.colors.textMuted }}> = </span>
            <span style={{ color: theme.colors.green, fontWeight: 700, fontSize: 13 }}>
              {selOutput.toFixed(1)}
            </span>
          </div>

          {/* Full vs Sparse comparison */}
          {windowSize < SEQ_LEN - 1 && (
            <div style={{
              marginTop: 8,
              fontSize: 10,
              color: theme.colors.textMuted,
              display: 'flex',
              gap: 16,
            }}>
              <span>
                Full attention output: <span style={{ color: theme.colors.yellow }}>{fullOutput.toFixed(1)}</span>
              </span>
              <span>
                Diff: <span style={{ color: Math.abs(selOutput - fullOutput) < 1 ? theme.colors.green : theme.colors.orange }}>
                  {Math.abs(selOutput - fullOutput) < 0.05 ? 'none' : (selOutput - fullOutput > 0 ? '+' : '') + (selOutput - fullOutput).toFixed(1)}
                </span>
              </span>
            </div>
          )}
        </div>

        {/* Key Insight */}
        <div style={{
          background: theme.colors.surfaceAlt,
          borderRadius: 8,
          padding: '10px 14px',
          fontSize: 11,
          color: theme.colors.textSecondary,
          borderLeft: '3px solid ' + theme.colors.primary,
          lineHeight: 1.5,
        }}>
          <span style={{ color: theme.colors.primary, fontWeight: 600 }}>Why sparse? </span>
          {windowSize === 0 && 'Window = 0: each token sees ONLY itself. Output equals its own value. Fast (8 ops) but no context at all.'}
          {windowSize === 1 && 'Window = 1: each token sees 1 neighbor on each side. Local context captured with just ' + sparse.totalOps + ' ops instead of 64. Notice edge tokens (0, 7) have smaller windows!'}
          {windowSize === 2 && 'Window = 2: a moderate window captures nearby context. ' + sparse.totalOps + ' ops (' + opsPercent + '% of full). The diagonal band in the matrix = the sparse pattern that saves computation.'}
          {windowSize === 3 && 'Window = 3: wider context, but still ' + opsSaved + ' fewer ops than full attention. For sequences of length 1000, this difference is massive: 6K ops vs 1M!'}
          {windowSize >= 4 && windowSize < 7 && 'Window = ' + windowSize + ': getting close to full attention (' + opsPercent + '%). The band covers most of the matrix. The savings shrink, but for very long sequences even small reductions matter.'}
          {windowSize >= 7 && 'Window = 7: this IS full attention! Every token sees every other token. For 8 tokens its fine (64 ops), but for 1000 tokens thats 1,000,000 ops. Reduce the window to see how sparsity helps.'}
        </div>
      </div>
    </div>
  );
}
